pub enum WalkResultView {
    Valid { vbase: usize, pte: <PTE as View>::V },
    Invalid { vaddr: usize },
}

impl View for WalkResult {
    type V = WalkResultView;
    closed spec fn view(&self) -> WalkResultView {
        match self {
            WalkResult::Valid { vbase, pte } => WalkResultView::Valid { vbase: *vbase, pte: pte@ },
            WalkResult::Invalid { vaddr } => WalkResultView::Invalid { vaddr: *vaddr },
        }
    }
}

